var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"알콩달콜 블링블링 그레모리 바?","JPN":"ラブラブキラキラグレモリーのバー？","ENG":"\\"Happy Daze Magic Lounge Gremory's Bar?\\"","TWN":"七彩炫目的葛茉莉酒吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"네. 그레모리라는 이름을 쓰는 바는 이 가게 하나뿐입니다.","JPN":"はい。グレモリーを名前に使っているお店はここしかありません。","ENG":"Yes. This is the only bar around here that's named Gremory.","TWN":"對，這裡叫葛茉莉的酒吧，就只有這麼一間。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"찾으시던 데가 여기 아닌가요?","JPN":"探していたお店はここじゃないですか？","ENG":"Isn't it what you're looking for?","TWN":"你要找的地方應該就是這裡吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하, 하지만 음침하지 않고 입구부터 알록달록하지 않나요?","JPN":"で、でも薄暗い感じもないし、入り口も鮮やかです。","ENG":"B-but it doesn't look gloomy at all... The entrance looks too colorful.","TWN":"可…可是它一點也不灰暗，從大門口就很色彩繽紛欸？"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사악한 느낌도 전혀 없고…….","JPN":"邪悪な雰囲気も感じられませんし……","ENG":"It doesn't look evil, either...","TWN":"一點都沒有邪惡的感覺……"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"예? 그러면 무슨 문제라도 되는 건가요?","JPN":"え？　それだと何か問題でもあるんですか？","ENG":"Huh? Is that a problem?","TWN":"嗯？這有什麼問題嗎？"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 아무것도 아니에요! 직접 안내해 주셔서 감사합니다!","JPN":"な、なんでもありません！　ここまで案内してくれてありがとうございます！","ENG":"N-never mind. Thank you for showing me the way here.","TWN":"喔，沒有啦！謝謝你替我帶路！"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"감사는요. 제 목숨을 구해주신 은인이신데 이 정돈 당연히 해 드려야죠.","JPN":"いえいえ。命を救ってくれた恩人なので、このくらい当然です。","ENG":"You're welcome. You saved my life! It's the least I can do.","TWN":"沒什麼好謝的，你可是我的救命恩人，這點小忙是我應該幫的！"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"그럼 전 이만…","JPN":"それでは私はこれで……","ENG":"Goodbye, then.","TWN":"那我就先走一步…"},"stage":{"bg":"BAR_ENTRY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기가 악마가 있다는 술집…….","JPN":"ここが悪魔がいると言われている酒場……","ENG":"So, this is the devilish bar...","TWN":"這裡面有魔鬼嗎……"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"입구부터 제가 생각하던 분위기와는 좀 다르네요.","JPN":"入口からすでに思っていた雰囲気とは少し違いますね。","ENG":"The entrance looks totally different from what I expected.","TWN":"怎麼從大門感覺就和我的認知不太一樣？"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 펜듈럼은 이곳에서도 여전히 반응하고 있어요.","JPN":"でもペンデュラムはここでも相変わらず反応しています。","ENG":"But my pendulum is reacting to this place as well.","TWN":"不過鐘擺對這裡也有反應！"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇다는 건… 멀리서도 반응할 정도로 강력한 악마라는 뜻이겠죠.","JPN":"ということは……遠くからでも反応するような強力な悪魔ということでしょう。","ENG":"That means... the devil is so powerful that its presence can be detected even from far away.","TWN":"意思就是…這裡的魔鬼強到，在很遠的地方也感應得到吧！"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……정말 저 혼자서도 괜찮은 거겠죠?","JPN":"……本当に私一人でも大丈夫でしょうか？","ENG":"... I can do this alone, right?","TWN":"……我自己一個人真的可以嗎？"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"지상에 올라온 악마들은 교활해서 쉽게 정체를 드러내지 않는다고 하던데…….","JPN":"地上にでて来た悪魔たちは狡猾で簡単には正体を現さないそうですが……","ENG":"I was told devils on earth are cunning and rarely expose themselves...","TWN":"我聽說地上的魔鬼都很狡猾，不會輕易露出真面目……"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마를 직접 본 적도 없는 제가 과연 악마를 찾아낼 수 있을지 걱정이네요.","JPN":"悪魔を直接見たこともない私が、果たして悪魔を見つけられるか心配です。","ENG":"I've never seen a devil before. I don't know if I can even find one.","TWN":"我又沒親眼看過魔鬼，真的有辦法揪出魔鬼來嗎？"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"분명 쉽지 않겠지만… 시간은 충분하니 차근차근 찾아보면 되겠죠!","JPN":"きっと簡単ではないと思いますが……時間は十分あるので、慎重に探していけば大丈夫でしょう！","ENG":"It won't be easy, but I've got plenty of time. I'll take one step at a time!","TWN":"感覺就是個大難題…反正時間很充裕，我就慢慢地找吧！"},"stage":{"bg":"BAR_ENTRY_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};